#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define MAX_PD (3.0e6f)
#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f
#define FACTOR_CHIP 0.5f

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    const int num_iterations,
    __global const float *power,
    __global const float *temp_in,
    __global float *temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step
)
{
    int global_col = get_global_id(0);
    int global_row = get_global_id(1);

    int total_cols = col;
    int total_rows = row;

    // Calculate 1/R values for convenience (as in original code)
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float Cap_1 = step / Cap;

    for (int iter = 0; iter < num_iterations; iter++) {
        // Bounds check
        if (global_row < total_rows && global_col < total_cols) {
            int idx = global_row * total_cols + global_col;
            float delta;

            // Boundary conditions
            if (global_row == 0 || global_col == 0 || global_row == total_rows - 1 || global_col == total_cols - 1) {
                if (global_row == 0 && global_col == 0) {
                    delta = Cap_1 * (power[0] +
                        (temp_in[1] - temp_in[0]) * Rx_1 +
                        (temp_in[total_cols] - temp_in[0]) * Ry_1 +
                        (amb_temp - temp_in[0]) * Rz_1);
                }
                else if (global_row == 0 && global_col == total_cols - 1) {
                    delta = Cap_1 * (power[global_col] +
                        (temp_in[global_col - 1] - temp_in[global_col]) * Rx_1 +
                        (temp_in[global_col + total_cols] - temp_in[global_col]) * Ry_1 +
                        (amb_temp - temp_in[global_col]) * Rz_1);
                }
                else if (global_row == total_rows - 1 && global_col == total_cols - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                        (temp_in[idx - total_cols] - temp_in[idx]) * Ry_1 +
                        (amb_temp - temp_in[idx]) * Rz_1);
                }
                else if (global_row == total_rows - 1 && global_col == 0) {
                    delta = Cap_1 * (power[global_row * total_cols] +
                        (temp_in[global_row * total_cols + 1] - temp_in[global_row * total_cols]) * Rx_1 +
                        (temp_in[(global_row - 1) * total_cols] - temp_in[global_row * total_cols]) * Ry_1 +
                        (amb_temp - temp_in[global_row * total_cols]) * Rz_1);
                }
                else if (global_row == 0) {
                    delta = Cap_1 * (power[global_col] +
                        (temp_in[global_col + 1] + temp_in[global_col - 1] - 2.0f * temp_in[global_col]) * Rx_1 +
                        (temp_in[total_cols + global_col] - temp_in[global_col]) * Ry_1 +
                        (amb_temp - temp_in[global_col]) * Rz_1);
                }
                else if (global_col == total_cols - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_in[(global_row + 1) * total_cols + global_col] + temp_in[(global_row - 1) * total_cols + global_col] - 2.0f * temp_in[idx]) * Ry_1 +
                        (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                        (amb_temp - temp_in[idx]) * Rz_1);
                }
                else if (global_row == total_rows - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_in[global_row * total_cols + global_col + 1] + temp_in[global_row * total_cols + global_col - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                        (temp_in[(global_row - 1) * total_cols + global_col] - temp_in[idx]) * Ry_1 +
                        (amb_temp - temp_in[idx]) * Rz_1);
                }
                else if (global_col == 0) {
                    delta = Cap_1 * (power[global_row * total_cols] +
                        (temp_in[(global_row + 1) * total_cols] + temp_in[(global_row - 1) * total_cols] - 2.0f * temp_in[global_row * total_cols]) * Ry_1 +
                        (temp_in[global_row * total_cols + 1] - temp_in[global_row * total_cols]) * Rx_1 +
                        (amb_temp - temp_in[global_row * total_cols]) * Rz_1);
                }
                else {
                    delta = 0.0f; // Should not reach here
                }
                temp_out[idx] = temp_in[idx] + delta;
            }
            else {
                // Interior points
                float val = temp_in[idx] + Cap_1 * (power[idx] +
                    (temp_in[(global_row + 1) * total_cols + global_col] + temp_in[(global_row - 1) * total_cols + global_col] - 2.0f * temp_in[idx]) * Ry_1 +
                    (temp_in[global_row * total_cols + global_col + 1] + temp_in[global_row * total_cols + global_col - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                    (amb_temp - temp_in[idx]) * Rz_1);
                temp_out[idx] = val;
            }
        }
        barrier(CLK_GLOBAL_MEM_FENCE);

        // Swap pointers for next iteration
        __global float *tmp = (iter % 2 == 0) ? temp_out : temp_in;
        __global float *src = (iter % 2 == 0) ? temp_out : temp_in;
        __global float *dst = (iter % 2 == 0) ? temp_in : temp_out;
        // Actually, because in OpenCL kernel, temp_in and temp_out are fixed pointers,
        // we cannot swap pointer variables as in CPU code.
        // So to simulate swapping buffers, caller should launch kernel multiple times with swapped buffers.
        // Here we perform all iterations in kernel for clarity, but this is only correct if temp_in and temp_out are the same buffer.
        // For now, we assume temp_in and temp_out are different buffers and only one iteration is done per call.
        // Thus, the caller should handle multiple iterations.
        // So break after first iteration
        break;
    }
}
